// ── CONSTANTES ───────────────────────────────────────────────
const THRESHOLDS = {
  meta_cpm_warning:   35,
  meta_cpm_critical:  50,
  meta_ctr_warning:   1.0,   // %
  meta_ctr_critical:  0.5,   // %
  meta_freq_warning:  3.5,
  meta_freq_critical: 5.0,
  meta_no_leads_days: 7,
  google_search_is_warning: 0.30,  // 30%
};

const supabaseUrl = $('Config').item.json.SUPABASE_URL;
const supabaseKey = $('Config').item.json.SUPABASE_KEY;
const dateYesterday = $('Config').item.json.DATE_YESTERDAY;

const metaRows = $('Buscar Meta D-1').all().map(i => i.json);
const meta7dRows = $('Buscar Meta 7 dias').all().map(i => i.json);
const googleRows = $('Buscar Google D-1').all().map(i => i.json);

// Agrupar meta 7d por account_id
const meta7dByAccount = {};
for (const r of meta7dRows) {
  if (!meta7dByAccount[r.account_id]) meta7dByAccount[r.account_id] = { total_leads: 0, total_spend: 0 };
  meta7dByAccount[r.account_id].total_leads += parseFloat(r.leads ?? 0);
  meta7dByAccount[r.account_id].total_spend += parseFloat(r.spend ?? 0);
}

const alerts = [];

// ── META ALERTS ────────────────────────────────────────────
for (const row of metaRows) {
  const cpm = parseFloat(row.cpm ?? 0);
  const ctr = parseFloat(row.ctr ?? 0) * 100;  // ctr is 0-1 in DB, convert to %
  const freq = parseFloat(row.frequency ?? 0);
  const leads = parseInt(row.leads ?? 0);
  const spend = parseFloat(row.spend ?? 0);
  const accountId = row.account_id;
  const accountName = row.account_name ?? accountId;

  // CPM
  if (cpm > THRESHOLDS.meta_cpm_critical) {
    alerts.push({
      platform: 'meta', severity: 'critical', category: 'cpm',
      entity_type: 'account', entity_id: accountId, entity_name: accountName,
      metric: 'cpm', current_value: cpm, threshold_value: THRESHOLDS.meta_cpm_critical,
      account_id: accountId, account_name: accountName, date: dateYesterday,
      message: `CPM crítico: ${accountName} — R$${cpm.toFixed(2)} (limite: R$${THRESHOLDS.meta_cpm_critical})`,
      recommendation: 'Revisar segmentações e criativos. CPM elevado indica baixa relevância do anúncio.',
      is_resolved: false
    });
  } else if (cpm > THRESHOLDS.meta_cpm_warning) {
    alerts.push({
      platform: 'meta', severity: 'warning', category: 'cpm',
      entity_type: 'account', entity_id: accountId, entity_name: accountName,
      metric: 'cpm', current_value: cpm, threshold_value: THRESHOLDS.meta_cpm_warning,
      account_id: accountId, account_name: accountName, date: dateYesterday,
      message: `CPM elevado: ${accountName} — R$${cpm.toFixed(2)} (limite: R$${THRESHOLDS.meta_cpm_warning})`,
      recommendation: 'Monitorar frequência e qualidade dos criativos.',
      is_resolved: false
    });
  }

  // CTR
  if (ctr < THRESHOLDS.meta_ctr_critical) {
    alerts.push({
      platform: 'meta', severity: 'critical', category: 'ctr',
      entity_type: 'account', entity_id: accountId, entity_name: accountName,
      metric: 'ctr', current_value: ctr, threshold_value: THRESHOLDS.meta_ctr_critical,
      account_id: accountId, account_name: accountName, date: dateYesterday,
      message: `CTR crítico: ${accountName} — ${ctr.toFixed(2)}% (mínimo: ${THRESHOLDS.meta_ctr_critical}%)`,
      recommendation: 'Pausar criativos de baixo desempenho. Testar novos formatos e copies.',
      is_resolved: false
    });
  } else if (ctr < THRESHOLDS.meta_ctr_warning) {
    alerts.push({
      platform: 'meta', severity: 'warning', category: 'ctr',
      entity_type: 'account', entity_id: accountId, entity_name: accountName,
      metric: 'ctr', current_value: ctr, threshold_value: THRESHOLDS.meta_ctr_warning,
      account_id: accountId, account_name: accountName, date: dateYesterday,
      message: `CTR abaixo do benchmark: ${accountName} — ${ctr.toFixed(2)}%`,
      recommendation: 'Avaliar qualidade dos criativos e relevância da segmentação.',
      is_resolved: false
    });
  }

  // Frequência
  if (freq > THRESHOLDS.meta_freq_critical) {
    alerts.push({
      platform: 'meta', severity: 'critical', category: 'frequency',
      entity_type: 'account', entity_id: accountId, entity_name: accountName,
      metric: 'frequency', current_value: freq, threshold_value: THRESHOLDS.meta_freq_critical,
      account_id: accountId, account_name: accountName, date: dateYesterday,
      message: `Frequência crítica: ${accountName} — ${freq.toFixed(1)}x (limite: ${THRESHOLDS.meta_freq_critical}x)`,
      recommendation: 'Renovar criativos urgentemente. Considerar ampliar audiência.',
      is_resolved: false
    });
  } else if (freq > THRESHOLDS.meta_freq_warning) {
    alerts.push({
      platform: 'meta', severity: 'warning', category: 'frequency',
      entity_type: 'account', entity_id: accountId, entity_name: accountName,
      metric: 'frequency', current_value: freq, threshold_value: THRESHOLDS.meta_freq_warning,
      account_id: accountId, account_name: accountName, date: dateYesterday,
      message: `Frequência elevada: ${accountName} — ${freq.toFixed(1)}x`,
      recommendation: 'Planejar renovação de criativos nos próximos dias.',
      is_resolved: false
    });
  }

  // Zero leads em 7 dias
  const week = meta7dByAccount[accountId];
  if (week && week.total_spend > 50 && week.total_leads === 0) {
    alerts.push({
      platform: 'meta', severity: 'critical', category: 'leads',
      entity_type: 'account', entity_id: accountId, entity_name: accountName,
      metric: 'leads_7d', current_value: 0, threshold_value: 1,
      account_id: accountId, account_name: accountName, date: dateYesterday,
      message: `Zero leads em 7 dias: ${accountName} (R$${week.total_spend.toFixed(0)} investidos)`,
      recommendation: 'Verificar pixel, formulário e otimização da campanha.',
      is_resolved: false
    });
  }
}

// ── GOOGLE ALERTS ──────────────────────────────────────────
for (const row of googleRows) {
  const is = parseFloat(row.search_impression_share ?? 0);
  const accountId = row.account_id;
  const accountName = row.account_name ?? accountId;
  const spend = parseFloat(row.spend ?? 0);

  // Search IS baixo
  if (is > 0 && is < THRESHOLDS.google_search_is_warning) {
    const lostBudget = parseFloat(row.search_lost_is_budget ?? 0);
    const reason = lostBudget > 0.2 ? 'por orçamento' : 'por qualidade/lance';
    alerts.push({
      platform: 'google', severity: 'warning', category: 'impression_share',
      entity_type: 'account', entity_id: accountId, entity_name: accountName,
      metric: 'search_impression_share', current_value: is * 100, threshold_value: THRESHOLDS.google_search_is_warning * 100,
      account_id: accountId, account_name: accountName, date: dateYesterday,
      message: `Search IS baixo: ${accountName} — ${(is * 100).toFixed(1)}% (perdendo ${reason})`,
      recommendation: lostBudget > 0.2
        ? 'Considerar aumentar o budget diário da campanha.'
        : 'Revisar Quality Score das keywords e lances.',
      is_resolved: false
    });
  }

  // Zero conversões com gasto significativo
  const conversions = parseFloat(row.conversions ?? 0);
  if (spend > 100 && conversions === 0) {
    alerts.push({
      platform: 'google', severity: 'warning', category: 'conversions',
      entity_type: 'account', entity_id: accountId, entity_name: accountName,
      metric: 'conversions', current_value: 0, threshold_value: 1,
      account_id: accountId, account_name: accountName, date: dateYesterday,
      message: `Zero conversões: ${accountName} investiu R$${spend.toFixed(0)} sem converter`,
      recommendation: 'Verificar tag de conversão e landing page. Revisar match types das keywords.',
      is_resolved: false
    });
  }
}

// Retorna os alertas gerados com credenciais Supabase
return alerts.map(alert => ({
  json: {
    ...alert,
    _supabase_url: supabaseUrl,
    _supabase_key: supabaseKey
  }
}));
